// Handler factory — dependency injected via closure
func NewUserHandler(svc UserService) gin.HandlerFunc {
	return func(c *gin.Context) {
		id := c.Param("id")
		user, err := svc.GetByID(c.Request.Context(), id)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
			return
		}
		c.JSON(http.StatusOK, user)
	}
}

// Router wiring — dependencies composed outside Gin
func SetupRouter(svc UserService) *gin.Engine {
	r := gin.New()
	r.GET("/users/:id", NewUserHandler(svc))
	return r
}

// N+1 anti-pattern inside a gin handler
func GetPostsNaive(c *gin.Context) {
	var posts []Post
	db.Find(&posts)
	for i := range posts {
		db.Where("post_id = ?", posts[i].ID).Find(&posts[i].Comments) // 1 query per post
	}
	c.JSON(http.StatusOK, posts)
}

// Fix: Preload collapses N+1 into 2 queries
func GetPosts(c *gin.Context) {
	var posts []Post
	if err := db.Preload("Comments").Find(&posts).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, posts)
}

type CreatePostRequest struct {
	Title   string `json:"title" binding:"required,min=3,max=120"`
	Content string `json:"content" binding:"required,max=5000"`
	Email   string `json:"email" binding:"required,email"`
}

func CreatePost(c *gin.Context) {
	var req CreatePostRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		var ve validator.ValidationErrors
		if errors.As(err, &ve) {
			out := make([]gin.H, len(ve))
			for i, fe := range ve {
				out[i] = gin.H{"field": fe.Field(), "message": fe.Tag()}
			}
			c.JSON(http.StatusUnprocessableEntity, gin.H{"errors": out})
			return
		}
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request"})
		return
	}
	req.Content = bluemonday.StrictPolicy().Sanitize(req.Content)
	c.JSON(http.StatusCreated, gin.H{"status": "ok"})
}

func AuthMiddleware(secret []byte) gin.HandlerFunc {
	return func(c *gin.Context) {
		tokenStr := strings.TrimPrefix(c.GetHeader("Authorization"), "Bearer ")
		token, err := jwt.ParseWithClaims(tokenStr, &Claims{}, func(t *jwt.Token) (interface{}, error) {
			if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
			}
			return secret, nil
		})
		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}
		c.Set("userID", token.Claims.(*Claims).UserID)
		c.Next()
	}
}

type AppError struct {
	Status  int    `json:"-"`
	Code    string `json:"code"`
	Message string `json:"message"`
}
func (e *AppError) Error() string { return e.Message }

func ErrorHandler() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Next()
		if len(c.Errors) == 0 {
			return
		}
		var appErr *AppError
		if errors.As(c.Errors.Last().Err, &appErr) {
			c.JSON(appErr.Status, appErr)
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"code": "INTERNAL", "message": "unexpected error"})
		}
	}
}

